mapper.select:
SELECT e.event_id, e.title, e.event_date, e.end_date, e.location, e.description, e.capacity, e.organizer, e.status, COUNT(a.apply_id) AS applicant_count, e.reg_date FROM erp_event e LEFT JOIN erp_event_apply a ON e.event_id = a.event_id AND a.status = 'CONFIRM' WHERE e.status = 'COMPLETE'
AND e.title LIKE '%' || #{keyword} || '%'
GROUP BY e.event_id, e.title, e.event_date, e.end_date, e.location, e.description, e.capacity, e.organizer, e.status, e.reg_date ORDER BY e.event_date DESC LIMIT #{limit} OFFSET #{offset}
